// Permission-grant history — who granted what to whom, when.
// Generated by flowforge JTBD generator — do not edit by hand.
import * as React from "react";

import { adminApi, type AdminGrantHistoryEntry } from "../api";

export function PermissionsHistory(): React.ReactElement {
	const [rows, setRows] = React.useState<ReadonlyArray<AdminGrantHistoryEntry>>([]);
	const [error, setError] = React.useState<string | null>(null);
	const [busy, setBusy] = React.useState(false);
	const [actionFilter, setActionFilter] = React.useState<"all" | "granted" | "revoked">("all");

	const load = React.useCallback(async () => {
		setBusy(true);
		setError(null);
		try {
			setRows(await adminApi.listGrantHistory());
		} catch (e: unknown) {
			setError(e instanceof Error ? e.message : "load failed");
		} finally {
			setBusy(false);
		}
	}, []);

	React.useEffect(() => {
		void load();
	}, [load]);

	const visible = rows.filter((r) => actionFilter === "all" || r.action === actionFilter);

	return (
		<section aria-labelledby="grants-heading">
			<h2 id="grants-heading">Permission grants</h2>
			<p className="ff-admin-hint">
				Append-only history of grant/revoke actions sourced from{" "}
				<code>AccessGrantPort</code>. Entries cannot be edited or deleted; the
				audit chain provides the tamper-evidence guarantee.
			</p>
			<form
				className="ff-admin-filters"
				onSubmit={(e) => {
					e.preventDefault();
					void load();
				}}
			>
				<label>
					Action
					<select
						value={actionFilter}
						onChange={(e) => setActionFilter(e.target.value as typeof actionFilter)}
					>
						<option value="all">all</option>
						<option value="granted">granted</option>
						<option value="revoked">revoked</option>
					</select>
				</label>
				<button type="submit" disabled={busy}>
					{busy ? "Loading…" : "Refresh"}
				</button>
			</form>
			{error ? (
				<p role="alert" className="ff-admin-error">
					{error}
				</p>
			) : null}
			<table className="ff-admin-table">
				<thead>
					<tr>
						<th scope="col">when</th>
						<th scope="col">tenant</th>
						<th scope="col">granter</th>
						<th scope="col">grantee</th>
						<th scope="col">permission</th>
						<th scope="col">action</th>
					</tr>
				</thead>
				<tbody>
					{visible.map((row) => (
						<tr key={row.id}>
							<td>
								<time dateTime={row.created_at}>{row.created_at}</time>
							</td>
							<td>{row.tenant_id}</td>
							<td>{row.granter}</td>
							<td>{row.grantee}</td>
							<td>
								<code>{row.permission}</code>
							</td>
							<td>
								<span className={`ff-admin-status ff-admin-status-${row.action}`}>
									{row.action}
								</span>
							</td>
						</tr>
					))}
					{visible.length === 0 && !busy ? (
						<tr>
							<td colSpan={6}>no grant history</td>
						</tr>
					) : null}
				</tbody>
			</table>
		</section>
	);
}
